func resolveWorkflowRoot(flag, filterRepo string) string {
	flag = strings.TrimSpace(flag)
	if flag != "" {
		return flag
	}
	if filterRepo != "" {
		if st, err := os.Stat(".github/workflows"); err == nil && st.IsDir() {
			return "."
		}
	}
	return ""
}

